import{_ as s,C as r,o as n,c as l,ag as o,j as t,a,E as p}from"./chunks/framework.CbQjVMS6.js";const d="/assets/powerpack-drag.CaLG0O7w.gif",c="/assets/wabbitemu-drag.YakzKITL.gif",y=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md","lastUpdated":1774326589000}'),h={name:"getting-started.md"};function u(g,e,m,k,f,b){const i=r("Badge");return n(),l("div",null,[e[7]||(e[7]=o('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Powerpack is designed for writing TI Basic 8XP programs which run on the following Texas Instruments calculators:</p><ul class="green-ticks"><li>TI-83 Plus</li><li>TI-84 Plus (monochrome screen)</li><li>TI-84 Plus SE (Silver Edition, monochrome screen)</li><li>TI-84 Plus CSE (colour screen)</li><li>TI-84 Plus CE (colour screen)</li></ul><p>It will probably <em>not</em> work for 68k TI Basic or TI-Nspire Basic, which runs on the TI-89, TI-92, Voyage 200, and TI-Nspire.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2>',5)),t("ul",null,[e[5]||(e[5]=t("li",null,[t("strong",null,"Windows 7 or above"),a(" — Powerpack is primarily tested on Microsoft Windows"),t("br"),a(" (although it is possible to run Powerpack on Mac OS using "),t("a",{href:"https://www.winehq.org/",target:"_blank",rel:"noreferrer"},"Wine"),a(")")],-1)),e[6]||(e[6]=t("li",null,[t("strong",null,[t("a",{href:"https://education.ti.com/en/software/details/en/CA9C74CAD02440A69FDC7189D7E1B6C2/swticonnectcesoftware",target:"_blank",rel:"noreferrer"},"TI Connect CE")]),a(" (Texas’ recommended editor) for writing code and for transferring your programs to the calculator. You can also write code in any text editor, such as VSCode. "),t("a",{href:"/features/compile-to-8xp"},"Learn more here"),a(".")],-1)),t("li",null,[e[0]||(e[0]=t("a",{href:"http://wabbitemu.org/",target:"_blank",rel:"noreferrer"},"WabbitEmu",-1)),e[1]||(e[1]=a()),p(i,{type:"info",text:"Optional"}),e[2]||(e[2]=a(" — the recommended emulator for testing your 8XP programs on your computer, before transferring them to your calculator. You’ll also need a ",-1)),e[3]||(e[3]=t("a",{href:"https://web.archive.org/web/20240409191813/http://tiroms.weebly.com/",target:"_blank",rel:"noreferrer"},"ROM image",-1)),e[4]||(e[4]=a(" for your particular calculator.",-1))])]),e[8]||(e[8]=o(`<h2 id="installing" tabindex="-1">Installing <a class="header-anchor" href="#installing" aria-label="Permalink to &quot;Installing&quot;">​</a></h2><p><a href="#xxxxxxxxxxxx">Download Powerpack.exe</a> and place it in a folder of your choice.</p><p>You may like to place it in the same folder as your 8XP programs, which can make using it easier, but this is optional.</p><h2 id="quickstart-tutorial" tabindex="-1">Quickstart tutorial <a class="header-anchor" href="#quickstart-tutorial" aria-label="Permalink to &quot;Quickstart tutorial&quot;">​</a></h2><ol><li><p>Ensure you have the necessary applications installed, as listed above</p></li><li><p><strong><a href="#xxxxxxxxxx">Download Powerpack</a></strong> and place it in the same folder as your 8XP program</p></li><li><p>In <strong>TI Connect CE</strong>, copy and paste the following code into a new program, set the “Var Name” to <code>HELLO</code>, and save it as <code>HELLO.8xp</code></p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="HELLO.8xp">HELLO.8xp</span></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#define</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> @Name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> John</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Say hello, 3 times</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">For(I,1,3)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Disp &quot;Hello </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">@Name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">End</span></span></code></pre></div></div></li><li><p>In Windows Explorer, drag and drop your program onto <code>Powerpack.exe</code></p><p><img src="`+d+`" alt="Powerpack drag and drop"></p><p>It will process the code, removing comments and whitespace, and save the result into:<br><code>Compiled Programs\\HELLO.optimized.8xp</code></p><p>The compiled code will look something like this (you can open it to check):</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="Compiled Programs\\HELLO.optimized.8xp">Compiled Programs\\HELLO.optimized.8xp</span></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">For(I,1,3)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Disp &quot;Hello John</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">End</span></span></code></pre></div></div></li><li><p>Drag and drop the compiled file into WabbitEmu to load it, then press <kbd>PRGM</kbd> to run it. Or you can load the file onto your calculator and run it from there.</p><p>Be sure to transfer the <code>HELLO.optimized.8xp</code> file <em><strong>NOT</strong></em> the original <code>HELLO.8xp</code> file.</p><p><img src="`+c+'" alt=""></p></li></ol><p>You can use Powerpack just like we have done above, but to avoid the dragging and dropping steps, we can let Powerpack detect any changes to the file and load it into WabbitEmu automatically. Here’s how:</p><ol start="5"><li><p>Double click <code>Powerpack.exe</code>. It will open and pause, waiting for any changes to occur in 8XP files in the current folder.</p></li><li><p>Make a change to the original source code file. Perhaps change the name “John” to something else. Save the file.</p><p>Powerpack should detect the changed file, recompile it, and since WabbitEmu is currently running, it will load the updated file into WabbitEmu and even press the <kbd>ENTER</kbd> key to re-run it.</p><p>You should see the program re-run, this time with a different name printed on the screen.</p></li></ol><p>✅ Done!</p><p>Now you might like to explore the rest of this guide to find out other useful things you can do with Powerpack.</p><h2 id="ways-of-using-powerpack" tabindex="-1">Ways of using Powerpack <a class="header-anchor" href="#ways-of-using-powerpack" aria-label="Permalink to &quot;Ways of using Powerpack&quot;">​</a></h2><p>Depending on your preferred workflow, there are several ways you can use Powerpack:</p><ol><li><p><strong>Watch the current folder</strong>: place <code>Powerpack.exe</code> in the same folder as your 8XP files and double-click it to run. It will monitor the current folder for any changes to 8XP or 8XPPP files, and as soon as it sees a modification, it will automatically process and create an optimized version of that <code>.8XP</code> file.</p></li><li><p><strong>Process specific files</strong>: by dropping 8XP files onto <code>Powerpack.exe</code> (or specifying them on the command line) only those files will be processed and then <code>Powerpack.exe</code> will exit.</p></li><li><p><strong>Watch another folder</strong>: by dropping any folder onto <code>Powerpack.exe</code> that folder will be watched for any changes to 8XP or 8XPPP files and compilation will happen automatically.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also do a combination of the above by dropping both files and a folder onto <code>Powerpack.exe</code>. The files will be immediately processed, and then the folder will be watched for further changes.</p><p>Or you may like to setup a Windows shortcut or BAT file that specifies the files/folders to use, for example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Powerpack.exe &quot;My Programs\\MYPROG.8XP&quot; &quot;My Programs&quot;</span></span></code></pre></div></div>',13))])}const E=s(h,[["render",u]]);export{y as __pageData,E as default};
